example.code:
from typing import List, Dict, Any, Optional from dataclasses import dataclass
@dataclass class RetrievalConfig: initial_top_k: int = 50 rerank_top_k: int = 5 reranker: str = "cross-encoder" # cross-encoder, cohere, llm
class RerankingRAG: """RAG pipeline with reranking stage."""
def __init__( self, vector_store, embedding_service, config: RetrievalConfig = None ): self.vector_store = vector_store self.embedding_service = embedding_service self.config = config or RetrievalConfig()
# Initialize reranker if self.config.reranker == "cross-encoder": from sentence_transformers import CrossEncoder self.reranker = CrossEncoder('cross-encoder/ms-marco-MiniLM-L-12-v2') elif self.config.reranker == "cohere": import cohere self.reranker = cohere.Client()
def retrieve( self, query: str, filter: Optional[Dict] = None ) -> List[Dict[str, Any]]: """Two-stage retrieval with reranking.""" # Stage 1: Initial retrieval query_embedding = self.embedding_service.embed(query) initial_results = self.vector_store.search( query_embedding, top_k=self.config.initial_top_k, filter=filter )
documents = [r["content"] for r in initial_results]
# Stage 2: Reranking if self.config.reranker == "cross-encoder": reranked = self._cross_encoder_rerank(query, documents, initial_results) elif self.config.reranker == "cohere": reranked = self._cohere_rerank(query, documents, initial_results) else: reranked = self._llm_rerank(query, documents, initial_results)
return reranked[:self.config.rerank_top_k]
def _cross_encoder_rerank( self, query: str, documents: List[str], results: List[Dict] ) -> List[Dict]: """Cross-encoder reranking.""" pairs = [[query, doc] for doc in documents] scores = self.reranker.predict(pairs)
for i, result in enumerate(results): result["rerank_score"] = float(scores[i])
return sorted(results, key=lambda x: x["rerank_score"], reverse=True)
def _cohere_rerank( self, query: str, documents: List[str], results: List[Dict] ) -> List[Dict]: """Cohere reranking.""" response = self.reranker.rerank( query=query, documents=documents, top_n=self.config.rerank_top_k, model="rerank-english-v3.0" )
reranked = [] for r in response.results: result = results[r.index].copy() result["rerank_score"] = r.relevance_score reranked.append(result)
return reranked
def _llm_rerank( self, query: str, documents: List[str], results: List[Dict] ) -> List[Dict]: """LLM-based reranking.""" from llm_rerank import llm_rerank_with_scores rerank_results = llm_rerank_with_scores( query=query, documents=documents, top_k=self.config.rerank_top_k )
reranked = [] for r in rerank_results: result = results[r["index"]].copy() result["rerank_score"] = r["score"] reranked.append(result)
return reranked

